content.section:
Measuring Cache Efficiency in Production
Cache efficiency in production requires tracking at the call level, not the aggregate. A high average cache hit rate can mask critical patterns. Certain request types might have 0% cache hits due to prompt construction bugs, while others hit 99%.
```python import time from dataclasses import dataclass, field from collections import defaultdict from typing import Optional import anthropic
@dataclass class CacheMetrics: """Per-call caching metrics.""" timestamp: float endpoint: str cache_write_tokens: int cache_read_tokens: int uncached_input_tokens: int output_tokens: int latency_ms: float
@property def total_input_tokens(self) -> int: return self.cache_write_tokens + self.cache_read_tokens + self.uncached_input_tokens
@property def cache_hit_rate(self) -> float: if self.total_input_tokens == 0: return 0.0 return self.cache_read_tokens / self.total_input_tokens
def cost_anthropic_sonnet(self) -> float: """Calculate actual cost in dollars.""" return ( self.cache_write_tokens * 3.75e-6 + self.cache_read_tokens * 0.30e-6 + self.uncached_input_tokens * 3.00e-6 + self.output_tokens * 15.00e-6 )
def counterfactual_cost(self) -> float: """Cost if caching were disabled.""" return ( self.total_input_tokens * 3.00e-6 + self.output_tokens * 15.00e-6 )
class CacheMonitor: """Production cache efficiency monitor."""
def __init__(self): self._metrics: list[CacheMetrics] = [] self._by_endpoint: dict[str, list[CacheMetrics]] = defaultdict(list)
def record(self, metrics: CacheMetrics) -> None: self._metrics.append(metrics) self._by_endpoint[metrics.endpoint].append(metrics)
def summary(self, endpoint: Optional[str] = None) -> dict: data = self._by_endpoint[endpoint] if endpoint else self._metrics if not data: return {}
total_calls = len(data) total_cost = sum(m.cost_anthropic_sonnet() for m in data) counterfactual = sum(m.counterfactual_cost() for m in data) avg_hit_rate = sum(m.cache_hit_rate for m in data) / total_calls
return { "total_calls": total_calls, "avg_cache_hit_rate": f"{avg_hit_rate * 100:.1f}%", "total_cost": f"${total_cost:.4f}", "counterfactual_cost": f"${counterfactual:.4f}", "savings": f"${counterfactual - total_cost:.4f}", "savings_pct": f"{(1 - total_cost/counterfactual) * 100:.1f}%" if counterfactual > 0 else "N/A", "zero_hit_calls": sum(1 for m in data if m.cache_hit_rate == 0), }
def alert_low_cache_rate(self, threshold: float = 0.5) -> list[str]: """Return endpoint names with suspiciously low cache hit rates.""" alerts = [] for endpoint, metrics in self._by_endpoint.items(): if len(metrics) < 10: continue avg_hit = sum(m.cache_hit_rate for m in metrics[-50:]) / min(len(metrics), 50) if avg_hit < threshold: alerts.append( f"LOW CACHE HIT: {endpoint} averaging {avg_hit*100:.1f}% " f"(threshold: {threshold*100:.0f}%)" ) return alerts ```
**Key metrics to track in production:**
- **Cache hit rate by endpoint**: sudden drops indicate prompt construction changes that broke the cache prefix - **Cold start rate**: percentage of calls that triggered cache writes; high rates suggest TTL expiry or cache misses - **Cost per 1K calls by endpoint**: the most actionable metric; reveals which endpoints have optimization headroom - **TTFT (time to first token)**: cached calls should be 60-80% faster; deviations suggest cache misses
**Common diagnostic patterns:**
| Observation | Likely Cause | Fix | |---|---|---| | 0% cache hit on all calls | Dynamic content in stable layer | Move variable content after cache breakpoint | | Cache hit rate drops after deploy | Prompt template changed | Check for whitespace/formatting changes | | Cache hits but no latency reduction | Cache hit on small prefix only | Move cache boundary earlier in prompt | | High cache write rate | TTL expiring before reuse | Check call frequency vs 5-minute TTL | | Gemini cache not helping | <32K tokens in cache | Consolidate more content into cache |
